mapper.insert:
INSERT /* CmnIntmMdlMapper.insertIntmMdl */
	INTO CMN_INTM_MDL
	(
	  PRDT_ID				/* 모델ID */ 
	, RPRS_PRDT_ID			/* 대표모델ID */ 
	, RPRS_YN				/* 대표여부 */ 
	, PRDT_NM				/* 모델명 */ 
	, PRDT_CODE				/* 모델코드 */ 
	, PRDT_TYPE_CD			/* 모델유형코드 */ 
	, PRDT_IND_CD			/* 모델구분코드 */ 
	, PRDT_COLR_CD			/* 모델색상코드 */ 
	, MNFCT_ID				/* 제조사ID */ 
	, PRDT_LNCH_DT			/* 모델출시일자 */ 
	, PRDT_DT				/* 모델단종일자 */ 
	, REG_ID				/* 등록자ID */ 
	, REG_DTTM				/* 등록일시 */ 
	, RVISN_ID				/* 수정자ID */ 
	, RVISN_DTTM			/* 수정일시 */
	, NFC_USIM_YN			/* NFC지원여부 */
	)
VALUES
	(
	  #{prdtId, jdbcType=VARCHAR}
	, #{rprsPrdtId, jdbcType=VARCHAR}
	, #{rprsYn, jdbcType=VARCHAR}
	, #{prdtNm, jdbcType=VARCHAR}
	, UPPER(#{prdtCode, jdbcType=VARCHAR})
	, #{prdtTypeCd, jdbcType=VARCHAR}
	, #{prdtIndCd, jdbcType=VARCHAR}
	, #{prdtColrCd, jdbcType=VARCHAR}
	, #{mnfctId, jdbcType=VARCHAR}
	, #{prdtLnchDt, jdbcType=VARCHAR}
	, #{prdtDt, jdbcType=VARCHAR}
	, #{regId, jdbcType=VARCHAR}
	, SYSDATE
	, #{rvisnId, jdbcType=VARCHAR}
	, SYSDATE
	, #{nfcUsimYn, jdbcType=VARCHAR}
	)

mapper.update:
UPDATE CMN_INTM_MDL /* CmnIntmMdlMapper.updateIntmMdlPrdtDt */
SET
	RVISN_DTTM = SYSDATE
	, RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
				, PRDT_DT = #{prdtDt, jdbcType=VARCHAR} 				/* 모델단종일자 */
WHERE 1=1
	AND RPRS_PRDT_ID = #{rprsPrdtId}
	AND PRDT_DT >= (SELECT PRDT_DT
								FROM CMN_INTM_MDL
								WHERE 1=1
								AND RPRS_PRDT_ID = #{rprsPrdtId}
								AND RPRS_YN = 'Y'
								  )

