UPDATE CMN_INTM_MDL /* CmnIntmMdlMapper.updateIntmColrMdl */
SET
	RVISN_DTTM = SYSDATE
	, RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
			, PRDT_CODE = UPPER(#{prdtCode, jdbcType=VARCHAR}) 	/* 모델코드 */ 
		, PRDT_COLR_CD = #{prdtColrCd, jdbcType=VARCHAR} 		/* 모델색상코드 */
